                        return nil
                }
                info, err := os.Stat(path)
                if err != nil {
                        return err
                }
                st := info.Sys().(*syscall.Stat_t)
                rel, err := filepath.Rel(root, path)
                if err != nil {
                        return err
                }
                key := [2]uint64{uint64(st.Dev), uint64(st.Ino)}
                byIdentity[key] = append(byIdentity[key], filepath.ToSlash(rel))
